sys_business_rule.script:
// Reorder sequence numbers on update
(function executeRule(current, previous) {

    // Only proceed if number field has changed
    if (current.number !== previous.number) {
        var sequenceManager = new x_2025153_windsu_0.SequenceManager();
        var newNumber = parseInt(current.number);
        var oldNumber = parseInt(previous.number);

        // Reorder sequence to maintain consistency
        sequenceManager.reorderOnUpdate(
            current.getTableName(),
            'number',
            current.getValue('sys_id'),
            newNumber,
            oldNumber
        );
    }

})(current, previous);
